using HaCreator.MapEditor;using HaCreator.MapEditor.Info;using HaCreator.MapEditor.Instance;using HaCreator.MapEditor.UndoRedo;using HaSharedLibrary.Render.DX;using MapleLib.WzLib.WzStructure.Data;using Spine;using System;using System.Collections.Generic;using System.Windows;using System.Windows.Controls;using Loc=HaCreator.GUI.Localization.LocExtension;
namespace HaCreator.GUI.InstanceEditor{public partial class BackgroundInstanceEditor:EditorBase{private readonly BackgroundInstance item;private readonly BackgroundStateBackup initialState;public BackgroundInstanceEditor(BackgroundInstance item){InitializeComponent();this.item=item;initialState=new(item);Set(xInput,item.BaseX);Set(yInput,item.BaseY);Set(zInput,item.Z);zInput.IsEnabled=item.Z!=-1;pathLabel.Text=HaCreatorStateManager.CreateItemDescription(item);foreach(BackgroundType type in Enum.GetValues(typeof(BackgroundType)))typeBox.Items.Add(type.GetFriendlyName());typeBox.SelectedIndex=(int)item.type;Set(alphaBox,item.a);frontBox.IsChecked=item.front;flipBox.IsChecked=item.Flip;Set(pageInput,item.Page);Set(rxBox,item.rx);Set(ryBox,item.ry);Set(cxBox,item.cx);Set(cyBox,item.cy);foreach(RenderResolution r in Enum.GetValues(typeof(RenderResolution)))screenModeBox.Items.Add(new ComboBoxItem{Tag=r,Content=RenderResolutionExtensions.ToReadableString(r)});foreach(ComboBoxItem entry in screenModeBox.Items)if((int)(RenderResolution)entry.Tag==item.screenMode){screenModeBox.SelectedItem=entry;break;}if(screenModeBox.SelectedIndex<0)screenModeBox.SelectedIndex=0;BackgroundInfo info=(BackgroundInfo)item.BaseInfo;spineGroup.IsEnabled=info.WzSpineAnimationItem!=null||(info.Spine41AnimationNames?.Length??0)>0;if(info.WzSpineAnimationItem!=null)foreach(Animation animation in info.WzSpineAnimationItem.SkeletonData.Animations)spineAnimationBox.Items.Add(new ComboBoxItem{Tag=animation,Content=animation.Name});else if(info.Spine41AnimationNames!=null)foreach(string name in info.Spine41AnimationNames)spineAnimationBox.Items.Add(new ComboBoxItem{Tag=name,Content=name});foreach(ComboBoxItem entry in spineAnimationBox.Items)if(SpineName(entry)==item.SpineAni){spineAnimationBox.SelectedItem=entry;break;}spineRandomStartBox.IsChecked=item.SpineRandomStart;Type_Changed(null,null);}private static void Set(TextBox box,int value)=>InstanceEditorDialogSupport.SetInt(box,value);private int Get(TextBox box,int fallback=0)=>InstanceEditorDialogSupport.GetInt(box,fallback);protected override void cancelButton_Click(object s,EventArgs e)=>Close();protected override void okButton_Click(object s,EventArgs e){BackgroundType type=(BackgroundType)typeBox.SelectedIndex;int cx=Get(cxBox,item.cx),cy=Get(cyBox,item.cy);if((cy<0&&type!=BackgroundType.Regular)||(cx<0&&type==BackgroundType.Regular)){MessageBox.Show(Loc.Get("IE_BackgroundNegativeMessage"),Loc.Get("IE_InvalidBackgroundTitle"),MessageBoxButton.OK,MessageBoxImage.Error);return;}lock(item.Board.ParentControl){ApplyValues(type,cx,cy);BackgroundStateBackup finalState=new(item);item.Board.UndoRedoMan.AddUndoBatch(new List<UndoRedoAction>{new(item,UndoRedoType.BackgroundPropertiesChanged,initialState,finalState)});}Close();}private void ApplyValues(BackgroundType type,int cx,int cy){bool sort=false;int x=Get(xInput,item.BaseX),y=Get(yInput,item.BaseY),z=Get(zInput,item.Z);if(x!=item.BaseX||y!=item.BaseY)item.MoveBase(x,y);if(zInput.IsEnabled&&z!=item.Z){item.Z=z;sort=true;}bool front=frontBox.IsChecked==true;if(front!=item.front){(item.front?item.Board.BoardItems.FrontBackgrounds:item.Board.BoardItems.BackBackgrounds).Remove(item);(front?item.Board.BoardItems.FrontBackgrounds:item.Board.BoardItems.BackBackgrounds).Add(item);item.front=front;sort=true;}if(sort)item.Board.BoardItems.Sort();item.type=type;item.Flip=flipBox.IsChecked==true;item.Page=Get(pageInput,item.Page);item.a=Get(alphaBox,item.a);item.rx=Get(rxBox,item.rx);item.ry=Get(ryBox,item.ry);item.cx=cx;item.cy=cy;item.screenMode=screenModeBox.SelectedItem is ComboBoxItem screen?(int)(RenderResolution)screen.Tag:item.screenMode;item.SpineRandomStart=spineGroup.IsEnabled&&spineRandomStartBox.IsChecked==true;item.SpineAni=spineGroup.IsEnabled?SpineName(spineAnimationBox.SelectedItem as ComboBoxItem):null;}private static string SpineName(ComboBoxItem entry)=>entry?.Tag switch{Animation a=>a.Name,string s=>s,_=>null};private void Type_Changed(object s,SelectionChangedEventArgs e){if(typeDescription!=null&&typeBox.SelectedIndex>=0)typeDescription.Text=((BackgroundType)typeBox.SelectedIndex).GetDescription();}private void Cancel_Click(object s,RoutedEventArgs e)=>cancelButton_Click(s,EventArgs.Empty);private void Ok_Click(object s,RoutedEventArgs e)=>okButton_Click(s,EventArgs.Empty);}}
